  70 |             trace: None,
  71 |             workspace_folders: None,
  72 |         };
  73 | 
  74 |         let response = self
  75 |             .transport
  76 |             .request("initialize", Some(serde_json::to_value(params)?))
  77 |             .await?;
  78 | 
  79 |         if let Some(error) = response.error {
  80 |             return Err(anyhow::anyhow!("LSP initialize error: {}", error.message));
  81 |         }
  82 | 
