 /// A message in a conversation
 #[derive(Debug, Clone, Serialize, Deserialize)]
 pub struct Message {
     pub role: Role,
     pub content: Vec<ContentPart>,
 }

 #[derive(Debug, Clone, Copy, Serialize, Deserialize, PartialEq, Eq)]
 #[serde(rename_all = "lowercase")]
 pub enum Role {
     System,
     User,
     Assistant,
     Tool,
 }

 #[derive(Debug, Clone, Serialize, Deserialize)]
 #[serde(tag = "type", rename_all = "snake_case")]
 pub enum ContentPart {
     Text {
         text: String,
     },
     Image {
         url: String,
         mime_type: Option<String>,
     },
     File {
         path: String,
         mime_type: Option<String>,
     },
     ToolCall {
         id: String,
         name: String,
         arguments: String,
         /// Thought signature for Gemini 3.x models - must be passed back when sending tool results
         #[serde(skip_serializing_if = "Option::is_none")]
         thought_signature: Option<String>,
     },
     ToolResult {
         tool_call_id: String,
         content: String,
     },
     Thinking {
         text: String,
     },
 }

 /// Tool definition for the model
 #[derive(Debug, Clone, Serialize, Deserialize)]
 pub struct ToolDefinition {
     pub name: String,
     pub description: String,
     pub parameters: serde_json::Value, // JSON Schema
 }

 /// Request to generate a completion
 #[derive(Debug, Clone)]
 pub struct CompletionRequest {
     pub messages: Vec<Message>,
     pub tools: Vec<ToolDefinition>,
     pub model: String,
     pub temperature: Option<f32>,
     pub top_p: Option<f32>,
     pub max_tokens: Option<usize>,
     pub stop: Vec<String>,
 }

 /// Request to generate embeddings
 #[derive(Debug, Clone)]
 pub struct EmbeddingRequest {
     pub model: String,
     pub inputs: Vec<String>,
 }

 /// Response from an embedding request
 #[derive(Debug, Clone)]
 pub struct EmbeddingResponse {
     pub embeddings: Vec<Vec<f32>>,
     pub usage: Usage,
 }

 /// A streaming chunk from the model
 #[derive(Debug, Clone)]
 pub enum StreamChunk {
     Text(String),
     ToolCallStart { id: String, name: String },
     ToolCallDelta { id: String, arguments_delta: String },
     ToolCallEnd { id: String },
     Done { usage: Option<Usage> },
     Error(String),
 }

 /// Token usage information
 #[derive(Debug, Clone, Default, Serialize, Deserialize)]
 pub struct Usage {
     pub prompt_tokens: usize,
     pub completion_tokens: usize,
     pub total_tokens: usize,
     pub cache_read_tokens: Option<usize>,
     pub cache_write_tokens: Option<usize>,
 }

 /// Response from a completion request
 #[derive(Debug, Clone)]
 pub struct CompletionResponse {
     pub message: Message,
     pub usage: Usage,
     pub finish_reason: FinishReason,
 }

 #[derive(Debug, Clone, Copy, Serialize, Deserialize, PartialEq, Eq)]
 #[serde(rename_all = "snake_case")]
 pub enum FinishReason {
     Stop,
     Length,
     ToolCalls,
     ContentFilter,
     Error,
 }

 /// Provider trait that all AI providers must implement
 #[async_trait]
 pub trait Provider: Send + Sync {
     /// Get the provider name
     fn name(&self) -> &str;

     /// List available models
     async fn list_models(&self) -> Result<Vec<ModelInfo>>;

     /// Generate a completion
     async fn complete(&self, request: CompletionRequest) -> Result<CompletionResponse>;

     /// Generate a streaming completion
     async fn complete_stream(
         &self,
         request: CompletionRequest,
     ) -> Result<futures::stream::BoxStream<'static, StreamChunk>>;

     /// Generate embeddings
     async fn embed(&self, _request: EmbeddingRequest) -> Result<EmbeddingResponse> {
         anyhow::bail!("Provider '{}' does not support embeddings", self.name())
     }
 }

 /// Information about a model
 #[derive(Debug, Clone, Serialize, Deserialize)]
 pub struct ModelInfo {
     pub id: String,
     pub name: String,
     pub provider: String,
     pub context_window: usize,
     pub max_output_tokens: Option<usize>,
     pub supports_vision: bool,
     pub supports_tools: bool,
     pub supports_streaming: bool,
     pub input_cost_per_million: Option<f64>,
     pub output_cost_per_million: Option<f64>,
 }

 /// Registry of available providers
 pub struct ProviderRegistry {
     providers: HashMap<String, Arc<dyn Provider>>,
 }

 impl std::fmt::Debug for ProviderRegistry {
     fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
         f.debug_struct("ProviderRegistry")
             .field("provider_count", &self.providers.len())
             .field("providers", &self.providers.keys().collect::<Vec<_>>())
             .finish()
     }
 }

 impl ProviderRegistry {
     pub fn new() -> Self {
         Self {
             providers: HashMap::new(),
         }
     }

     /// Register a provider (automatically wrapped with metrics instrumentation)
     pub fn register(&mut self, provider: Arc<dyn Provider>) {
         let name = provider.name().to_string();
         let wrapped = metrics::MetricsProvider::wrap(provider);
         self.providers.insert(name, wrapped);
     }

     /// Get a provider by name
     pub fn get(&self, name: &str) -> Option<Arc<dyn Provider>> {
         self.providers.get(name).cloned()
     }

     /// List all registered providers
     pub fn list(&self) -> Vec<&str> {
         self.providers.keys().map(|s| s.as_str()).collect()
     }

     /// Resolve a model string to a provider.
     ///
     /// Accepts model strings in formats:
     /// - "provider/model" (e.g., "openai/gpt-4o")
     /// - "model" (uses first available provider)
     ///
     /// Returns the provider and the model name to use.
     pub fn resolve_model(&self, model_str: &str) -> Result<(Arc<dyn Provider>, String)> {
         let (provider_name, model) = parse_model_string(model_str);

         if let Some(provider_name) = provider_name {
             // Normalize provider aliases
             let normalized = match provider_name {
                 "local-cuda" | "localcuda" => "local_cuda",
                 "zhipuai" => "zai",
                 other => other,
             };

             let provider = self.providers.get(normalized).cloned().ok_or_else(|| {
                 anyhow::anyhow!(
                     "Provider '{}' not found. Available: {:?}",
                     normalized,
                     self.list()
                 )
             })?;
             Ok((provider, model.to_string()))
         } else {
             // No provider specified - use first available
             let first_provider = self
                 .providers
                 .values()
                 .next()
                 .ok_or_else(|| anyhow::anyhow!("No providers available in registry"))?;
             Ok((first_provider.clone(), model_str.to_string()))
         }
     }

     /// Initialize with default providers from config
     pub async fn from_config(config: &crate::config::Config) -> Result<Self> {
         let mut registry = Self::new();

         // Always try to initialize OpenAI if key is available
         if let Some(provider_config) = config.providers.get("openai") {
             if let Some(api_key) = &provider_config.api_key {
                 registry.register(Arc::new(openai::OpenAIProvider::new(api_key.clone())?));
             }
         } else if let Ok(api_key) = std::env::var("OPENAI_API_KEY") {
             registry.register(Arc::new(openai::OpenAIProvider::new(api_key)?));
         }

         // Initialize Anthropic
         if let Some(provider_config) = config.providers.get("anthropic") {
             if let Some(api_key) = &provider_config.api_key {
                 let provider = if let Some(base_url) = provider_config.base_url.clone() {
                     anthropic::AnthropicProvider::with_base_url(
                         api_key.clone(),
                         base_url,
                         "anthropic",
                     )?
                 } else {
                     anthropic::AnthropicProvider::new(api_key.clone())?
                 };
                 registry.register(Arc::new(provider));
             }
         } else if let Ok(api_key) = std::env::var("ANTHROPIC_API_KEY") {
             registry.register(Arc::new(anthropic::AnthropicProvider::new(api_key)?));
         }

         // Initialize Google
         if let Some(provider_config) = config.providers.get("google") {
             if let Some(api_key) = &provider_config.api_key {
                 registry.register(Arc::new(google::GoogleProvider::new(api_key.clone())?));
             }
         } else if let Ok(api_key) = std::env::var("GOOGLE_API_KEY") {
             registry.register(Arc::new(google::GoogleProvider::new(api_key)?));
         }

         // Initialize Novita (OpenAI-compatible)
         if let Some(provider_config) = config.providers.get("novita")
             && let Some(api_key) = &provider_config.api_key
         {
             let base_url = provider_config
                 .base_url
                 .clone()
                 .unwrap_or_else(|| "https://api.novita.ai/openai/v1".to_string());
             registry.register(Arc::new(openai::OpenAIProvider::with_base_url(
                 api_key.clone(),
                 base_url,
                 "novita",
             )?));
         }

         // Initialize Bedrock via AWS credentials (env vars or ~/.aws/credentials)
         if let Some(creds) = bedrock::AwsCredentials::from_environment() {
             let region = bedrock::AwsCredentials::detect_region()
                 .unwrap_or_else(|| bedrock::DEFAULT_REGION.to_string());
             match bedrock::BedrockProvider::with_credentials(creds, region) {
                 Ok(p) => registry.register(Arc::new(p)),
                 Err(e) => tracing::warn!("Failed to init bedrock from AWS credentials: {}", e),
             }
         }

         let disable_env_fallback = std::env::var("CODETETHER_DISABLE_ENV_FALLBACK")
             .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
             .unwrap_or(false);
         if !disable_env_fallback {
             Self::register_env_fallbacks(&mut registry);
         } else {
             tracing::info!(
                 "Environment variable fallback disabled (CODETETHER_DISABLE_ENV_FALLBACK=1)"
             );
         }

         Ok(registry)
     }

     /// Initialize providers from HashiCorp Vault with configurable environment variable fallback.
     ///
     /// This loads API keys from Vault and creates providers dynamically.
     /// Supports OpenAI-compatible providers via base_url.
     ///
     /// # Security Model & Environment Variable Fallback
     ///
     /// By default, this function attempts to load credentials from Vault first. If a provider
     /// is not configured in Vault, it falls back to checking environment variables for common
     /// providers (OpenAI, Anthropic, Google, OpenRouter). This fallback behavior is intended
     /// for local development and testing convenience.
     ///
     /// **Security Consideration**: In production or security-conscious deployments, environment
     /// variable fallback may be undesirable because:
     /// - Environment variables can be leaked via logs, process listings, or container inspection
     /// - They may persist in shell history or configuration files
     /// - Multiple processes share the same environment, increasing attack surface
     ///
     /// # Disabling Environment Variable Fallback
     ///
     /// Set the environment variable `CODETETHER_DISABLE_ENV_FALLBACK=1` to disable all
     /// environment variable fallback for provider credentials. When set:
     /// - Only Vault-configured providers will be available
     /// - The `register_env_fallbacks()` step is skipped entirely
     /// - Bedrock auto-detection from `AWS_*` environment variables is also disabled
     ///
     /// ```bash
     /// # Security-hardened deployment (no env var fallback)
     /// export CODETETHER_DISABLE_ENV_FALLBACK=1
     /// codetether serve
     /// ```
     ///
     /// # Fallback Order
     ///
     /// 1. **Vault secrets** (primary source): `secret/data/codetether/providers/<provider_id>`
     /// 2. **Bedrock auto-detection** (if not in Vault): Reads `AWS_ACCESS_KEY_ID`, `AWS_SECRET_ACCESS_KEY`
     /// 3. **Environment variable fallback** (if enabled):
     ///    - `OPENAI_API_KEY` → OpenAI provider
     ///    - `ANTHROPIC_API_KEY` → Anthropic provider
     ///    - `GOOGLE_API_KEY` → Google provider
     ///    - `OPENROUTER_API_KEY` → OpenRouter provider
     ///
     /// # Default Behavior
     ///
     /// The default (without `CODETETHER_DISABLE_ENV_FALLBACK`) allows environment variable
     /// fallback for backward compatibility and developer convenience. This default is
     /// intentionally permissive to support local development workflows where Vault may
     /// not be available.
     ///
     /// # See Also
     ///
     /// - `register_env_fallbacks()` for the list of supported environment variables
     /// - `src/secrets/mod.rs` for Vault configuration details
     /// - `AGENTS.md` for security best practices regarding secrets management
     pub async fn from_vault() -> Result<Self> {
         let mut registry = Self::new();
         let disable_env_fallback = std::env::var("CODETETHER_DISABLE_ENV_FALLBACK")
             .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
             .unwrap_or(false);

         if let Some(manager) = crate::secrets::secrets_manager() {
             // List all configured providers from Vault
             let providers = manager.list_configured_providers().await?;
             tracing::info!("Found {} providers configured in Vault", providers.len());

             for provider_id in providers {
                 let secrets = match manager.get_provider_secrets(&provider_id).await? {
                     Some(s) => s,
                     None => continue,
                 };

                 // Handle Bedrock before api_key extraction since it can use
                 // AWS IAM credentials instead of an API key.
                 if matches!(provider_id.as_str(), "bedrock" | "aws-bedrock") {
                     let region = secrets
                         .extra
                         .get("region")
                         .and_then(|v| v.as_str())
                         .unwrap_or("us-east-1")
                         .to_string();

                     // Prefer SigV4 if AWS credentials are in Vault
                     let aws_key_id = secrets
                         .extra
                         .get("aws_access_key_id")
                         .and_then(|v| v.as_str());
                     let aws_secret = secrets
                         .extra
                         .get("aws_secret_access_key")
                         .and_then(|v| v.as_str());

                     let result = if let (Some(key_id), Some(secret)) = (aws_key_id, aws_secret) {
                         let creds = bedrock::AwsCredentials {
                             access_key_id: key_id.to_string(),
                             secret_access_key: secret.to_string(),
                             session_token: secrets
                                 .extra
                                 .get("aws_session_token")
                                 .and_then(|v| v.as_str())
                                 .map(|s| s.to_string()),
                         };
                         bedrock::BedrockProvider::with_credentials(creds, region)
                     } else if let Some(ref key) = secrets.api_key {
                         bedrock::BedrockProvider::with_region(key.clone(), region)
                     } else {
                         // Try auto-detecting from environment as last resort
                         if let Some(creds) = bedrock::AwsCredentials::from_environment() {
                             bedrock::BedrockProvider::with_credentials(creds, region)
                         } else {
                             Err(anyhow::anyhow!(
                                 "No AWS credentials or API key found for Bedrock"
                             ))
                         }
                     };

                     match result {
                         Ok(p) => registry.register(Arc::new(p)),
                         Err(e) => tracing::warn!("Failed to init {}: {}", provider_id, e),
                     }
                     continue;
                 }

                 // Handle Vertex AI GLM before api_key extraction since it uses
                 // service account JWT auth (no api_key needed).
                 if matches!(provider_id.as_str(), "vertex-glm" | "vertex-ai" | "gcp-glm") {
                     let sa_json = secrets
                         .extra
                         .get("service_account_json")
                         .and_then(|v| v.as_str());

                     if let Some(sa_json) = sa_json {
                         let project_id = secrets
                             .extra
                             .get("project_id")
                             .and_then(|v| v.as_str())
                             .or_else(|| secrets.extra.get("projectId").and_then(|v| v.as_str()))
                             .map(|s| s.to_string());

                         match vertex_glm::VertexGlmProvider::new(sa_json, project_id) {
                             Ok(p) => registry.register(Arc::new(p)),
                             Err(e) => tracing::warn!("Failed to init vertex-glm: {e}"),
                         }
                     } else {
                         tracing::warn!(
                             "vertex-glm provider requires service_account_json in Vault secrets"
                         );
                     }
                     continue;
                 }

                 // Handle Vertex AI Anthropic (Claude models via GCP)
                 // Uses service account JWT auth like vertex-glm
                 if matches!(
                     provider_id.as_str(),
                     "vertex-anthropic" | "vertex-claude" | "gcp-anthropic"
                 ) {
                     let sa_json = secrets
                         .extra
                         .get("service_account_json")
                         .and_then(|v| v.as_str());

                     if let Some(sa_json) = sa_json {
                         let project_id = secrets
                             .extra
                             .get("project_id")
                             .and_then(|v| v.as_str())
                             .or_else(|| secrets.extra.get("projectId").and_then(|v| v.as_str()))
                             .map(|s| s.to_string());

                         match vertex_anthropic::VertexAnthropicProvider::new(sa_json, project_id) {
                             Ok(p) => registry.register(Arc::new(p)),
                             Err(e) => tracing::warn!("Failed to init vertex-anthropic: {e}"),
                         }
                     } else {
                         tracing::warn!(
                             "vertex-anthropic provider requires service_account_json in Vault secrets"
                         );
                     }
                     continue;
                 }

                 // Handle OpenAI Codex (ChatGPT subscription) before generic api_key extraction.
                 // Prefer an exchanged OpenAI API key when available so modern /v1/responses
                 // surfaces (including WebSocket mode) use standard API auth. Fall back to
                 // ChatGPT OAuth credentials when no exchanged API key is available.
                 if matches!(provider_id.as_str(), "openai-codex" | "codex" | "chatgpt") {
                     let access_token = secrets.extra.get("access_token").and_then(|v| v.as_str());
                     let refresh_token = secrets.extra.get("refresh_token").and_then(|v| v.as_str());
                     let expires_at = secrets.extra.get("expires_at").and_then(|v| v.as_u64());
                     let id_token = secrets.extra.get("id_token").and_then(|v| v.as_str());
                     let chatgpt_account_id = secrets
                         .extra
                         .get("chatgpt_account_id")
                         .and_then(|v| v.as_str());
                     let exchanged_api_key =
                         secrets.api_key.as_deref().filter(|key| !key.is_empty());

                     if let Some(api_key) = exchanged_api_key {
                         let provider =
                             openai_codex::OpenAiCodexProvider::from_api_key(api_key.to_string());
                         registry.register(Arc::new(provider));
                     } else {
                         match (access_token, refresh_token, expires_at) {
                             (Some(access), Some(refresh), Some(expires)) => {
                                 let creds = openai_codex::OAuthCredentials {
                                     id_token: id_token.map(ToString::to_string),
                                     chatgpt_account_id: chatgpt_account_id.map(ToString::to_string),
                                     access_token: access.to_string(),
                                     refresh_token: refresh.to_string(),
                                     expires_at: expires,
                                 };
                                 let provider =
                                     openai_codex::OpenAiCodexProvider::from_credentials(creds);
                                 registry.register(Arc::new(provider));
                             }
                             _ => {
                                 tracing::warn!(
                                     "openai-codex provider requires OAuth access_token, refresh_token, and expires_at (or an exchanged api_key) in Vault secrets"
                                 );
                             }
                         }
                     }
                     continue;
                 }

                 // Handle Gemini Web (browser-cookie-based, no API key needed)
                 if matches!(provider_id.as_str(), "gemini-web") {
                     let cookies = secrets.extra.get("cookies").and_then(|v| v.as_str());

                     if let Some(cookies) = cookies {
                         match gemini_web::GeminiWebProvider::new(cookies.to_string()) {
                             Ok(p) => registry.register(Arc::new(p)),
                             Err(e) => tracing::warn!("Failed to init gemini-web: {e}"),
                         }
                     } else {
                         tracing::warn!(
                             "gemini-web provider requires \"cookies\" field in Vault secrets \
                              (tab-separated Cookie-Editor export)"
                         );
                     }
                     continue;
                 }

                 // Handle Local CUDA (no API key needed)
                 if matches!(
                     provider_id.as_str(),
                     "local-cuda" | "local_cuda" | "localcuda"
                 ) {
                     let model_name = secrets
                         .extra
                         .get("model_name")
                         .and_then(|v| v.as_str())
                         .or_else(|| secrets.extra.get("model").and_then(|v| v.as_str()))
                         .unwrap_or("qwen3.5-9b")
                         .to_string();
                     let model_path = secrets
                         .extra
                         .get("model_path")
                         .and_then(|v| v.as_str())
                         .map(ToString::to_string);
                     let tokenizer_path = secrets
                         .extra
                         .get("tokenizer_path")
                         .and_then(|v| v.as_str())
                         .map(ToString::to_string);
                     let architecture = secrets
                         .extra
                         .get("architecture")
                         .and_then(|v| v.as_str())
                         .map(ToString::to_string);

                     let provider = if let Some(path) = model_path {
                         local_cuda::LocalCudaProvider::with_paths(
                             model_name.clone(),
                             path,
                             tokenizer_path,
                             architecture,
                         )
                     } else {
                         local_cuda::LocalCudaProvider::new(model_name.clone())
                     };

                     match provider {
                         Ok(p) => {
                             tracing::info!(
                                 model = %model_name,
                                 "Registered Local CUDA provider from Vault"
                             );
                             registry.register(Arc::new(p));
                         }
                         Err(e) => tracing::warn!("Failed to init local-cuda: {}", e),
                     }
                     continue;
                 }

                 // Hugging Face endpoint (OpenAI-compatible embeddings API), API key optional.
                 if provider_id == "huggingface" {
                     if let Some(base_url) = secrets.base_url.clone() {
                         match openai::OpenAIProvider::with_base_url_optional_key(
                             secrets.api_key.clone(),
                             base_url,
                             "huggingface",
                         ) {
                             Ok(p) => registry.register(Arc::new(p)),
                             Err(e) => tracing::warn!("Failed to init huggingface: {}", e),
                         }
                     } else {
                         tracing::warn!("huggingface provider requires base_url in Vault secrets");
                     }
                     continue;
                 }

                 let api_key = match secrets.api_key {
                     Some(key) => key,
                     None => continue,
                 };

                 // Determine which provider implementation to use
                 match provider_id.as_str() {
                     // Native providers
                     "anthropic" | "anthropic-eu" | "anthropic-asia" => {
                         let base_url = secrets
                             .base_url
                             .clone()
                             .unwrap_or_else(|| "https://api.anthropic.com".to_string());
                         match anthropic::AnthropicProvider::with_base_url(
                             api_key,
                             base_url,
                             &provider_id,
                         ) {
                             Ok(p) => registry.register(Arc::new(p)),
                             Err(e) => tracing::warn!("Failed to init {}: {}", provider_id, e),
                         }
                     }
                     "google" | "google-vertex" => match google::GoogleProvider::new(api_key) {
                         Ok(p) => registry.register(Arc::new(p)),
                         Err(e) => tracing::warn!("Failed to init {}: {}", provider_id, e),
                     },
                     // StepFun - native provider (direct API, not via OpenRouter)
                     "stepfun" => match stepfun::StepFunProvider::new(api_key) {
                         Ok(p) => registry.register(Arc::new(p)),
                         Err(e) => tracing::warn!("Failed to init stepfun: {}", e),
                     },
                     // OpenRouter - native provider with support for extended response formats
                     "openrouter" => match openrouter::OpenRouterProvider::new(api_key) {
                         Ok(p) => registry.register(Arc::new(p)),
                         Err(e) => tracing::warn!("Failed to init openrouter: {}", e),
                     },
                     // Moonshot AI - native provider for Kimi models
                     "moonshotai" | "moonshotai-cn" => {
                         match moonshot::MoonshotProvider::new(api_key) {
                             Ok(p) => registry.register(Arc::new(p)),
                             Err(e) => tracing::warn!("Failed to init moonshotai: {}", e),
                         }
                     }
                     // GitHub Copilot providers require custom headers/token semantics
                     "github-copilot" => {
                         let result = if let Some(base_url) = secrets.base_url.clone() {
                             copilot::CopilotProvider::with_base_url(
                                 api_key,
                                 base_url,
                                 "github-copilot",
                             )
                         } else {
                             copilot::CopilotProvider::new(api_key)
                         };

                         match result {
                             Ok(p) => registry.register(Arc::new(p)),
                             Err(e) => tracing::warn!("Failed to init github-copilot: {}", e),
                         }
                     }
                     "github-copilot-enterprise" => {
                         let enterprise_url = secrets
                             .extra
                             .get("enterpriseUrl")
                             .and_then(|v| v.as_str())
                             .or_else(|| {
                                 secrets.extra.get("enterprise_url").and_then(|v| v.as_str())
                             });

                         let result = if let Some(base_url) = secrets.base_url.clone() {
                             copilot::CopilotProvider::with_base_url(
                                 api_key,
                                 base_url,
                                 "github-copilot-enterprise",
                             )
                         } else if let Some(url) = enterprise_url {
                             copilot::CopilotProvider::enterprise(api_key, url.to_string())
                         } else {
                             copilot::CopilotProvider::with_base_url(
                                 api_key,
                                 "https://api.githubcopilot.com".to_string(),
                                 "github-copilot-enterprise",
                             )
                         };

                         match result {
                             Ok(p) => registry.register(Arc::new(p)),
                             Err(e) => {
                                 tracing::warn!("Failed to init github-copilot-enterprise: {}", e)
                             }
                         }
                     }
                     // GLM-5 FP8 on Vast.ai serverless (vLLM OpenAI-compatible endpoint)
                     "glm5" | "glm-5-fp8" | "glm5-vastai" => {
                         let base_url = secrets.base_url.clone().unwrap_or_else(|| {
                             std::env::var("GLM5_BASE_URL")
                                 .unwrap_or_else(|_| "https://localhost:18000/v1".to_string())
                         });
                         let model_name = secrets
                             .extra
                             .get("model_name")
                             .and_then(|v| v.as_str())
                             .unwrap_or(glm5::DEFAULT_MODEL)
                             .to_string();
                         match glm5::Glm5Provider::with_model(api_key, base_url, model_name) {
                             Ok(p) => registry.register(Arc::new(p)),
                             Err(e) => tracing::warn!("Failed to init glm5: {}", e),
                         }
                     }

                     // Z.AI (formerly ZhipuAI) — first-class provider for GLM models
                     "zhipuai" | "zai" => {
                         let base_url = secrets
                             .base_url
                             .clone()
                             .unwrap_or_else(|| "https://api.z.ai/api/paas/v4".to_string());
                         match zai::ZaiProvider::with_base_url(api_key, base_url) {
                             Ok(p) => registry.register(Arc::new(p)),
                             Err(e) => tracing::warn!("Failed to init zai: {}", e),
                         }
                     }

                     // Cerebras - OpenAI-compatible fast inference
                     "cerebras" => {
                         let base_url = secrets
                             .base_url
                             .clone()
                             .unwrap_or_else(|| "https://api.cerebras.ai/v1".to_string());
                         match openai::OpenAIProvider::with_base_url(api_key, base_url, "cerebras") {
                             Ok(p) => registry.register(Arc::new(p)),
                             Err(e) => tracing::warn!("Failed to init cerebras: {}", e),
                         }
                     }
                     // MiniMax - Anthropic-compatible API harness (recommended by MiniMax docs)
                     // "minimax" uses the coding-plan key (regular models)
                     // "minimax-credits" uses the credits-based key (highspeed models)
                     "minimax" | "minimax-credits" => {
                         let base_url = secrets
                             .base_url
                             .clone()
                             .unwrap_or_else(|| "https://api.minimax.io/anthropic".to_string());
                         let base_url = normalize_minimax_anthropic_base_url(&base_url);
                         match anthropic::AnthropicProvider::with_base_url(
                             api_key,
                             base_url,
                             &provider_id,
                         ) {
                             Ok(p) => registry.register(Arc::new(p)),
                             Err(e) => tracing::warn!("Failed to init {}: {}", provider_id, e),
                         }
                     }
                     // OpenAI-compatible providers (with custom base_url)
                     "deepseek" | "groq" | "togetherai" | "fireworks-ai" | "mistral" | "nvidia"
                     | "alibaba" | "openai" | "azure" | "novita" => {
                         if let Some(base_url) = secrets.base_url.clone() {
                             match openai::OpenAIProvider::with_base_url(
                                 api_key,
                                 base_url,
                                 &provider_id,
                             ) {
                                 Ok(p) => registry.register(Arc::new(p)),
                                 Err(e) => tracing::warn!("Failed to init {}: {}", provider_id, e),
                             }
                         } else if provider_id == "openai" {
                             // OpenAI doesn't need a custom base_url
                             match openai::OpenAIProvider::new(api_key) {
                                 Ok(p) => registry.register(Arc::new(p)),
                                 Err(e) => tracing::warn!("Failed to init openai: {}", e),
                             }
                         } else if provider_id == "novita" {
                             let base_url = "https://api.novita.ai/openai/v1".to_string();
                             match openai::OpenAIProvider::with_base_url(
                                 api_key,
                                 base_url,
                                 &provider_id,
                             ) {
                                 Ok(p) => registry.register(Arc::new(p)),
                                 Err(e) => tracing::warn!("Failed to init {}: {}", provider_id, e),
                             }
                         } else {
                             tracing::warn!(
                                 "Provider {} has no built-in base_url; set base_url in Vault secrets",
                                 provider_id
                             );
                         }
                     }
                     // Unknown providers - try as OpenAI-compatible with base_url from API
                     other => {
                         if let Some(base_url) = secrets.base_url {
                             match openai::OpenAIProvider::with_base_url(api_key, base_url, other) {
                                 Ok(p) => registry.register(Arc::new(p)),
                                 Err(e) => tracing::warn!("Failed to init {}: {}", other, e),
                             }
                         } else {
                             tracing::debug!(
                                 "Unknown provider {} without base_url, skipping",
                                 other
                             );
                         }
                     }
                 }
             }
         } else {
             tracing::warn!("Vault not configured, no providers will be available from Vault");
         }

         // If Bedrock wasn't registered via Vault, try auto-detecting AWS credentials
         // (unless env fallback is disabled for security-hardened deployments)
         if !registry.providers.contains_key("bedrock")
             && !disable_env_fallback
             && let Some(creds) = bedrock::AwsCredentials::from_environment()
         {
             let region =
                 bedrock::AwsCredentials::detect_region().unwrap_or_else(|| "us-east-1".to_string());
             match bedrock::BedrockProvider::with_credentials(creds, region) {
                 Ok(p) => {
                     tracing::info!("Registered Bedrock provider from local AWS credentials");
                     registry.register(Arc::new(p));
                 }
                 Err(e) => tracing::warn!("Failed to init bedrock from AWS credentials: {}", e),
             }
         }

         // Fallback to environment variables for common providers if not registered via Vault
         // Skip this step if CODETETHER_DISABLE_ENV_FALLBACK is set for security-hardened deployments
         if !disable_env_fallback {
             Self::register_env_fallbacks(&mut registry);
         } else {
             tracing::info!(
                 "Environment variable fallback disabled (CODETETHER_DISABLE_ENV_FALLBACK=1)"
             );
         }

         tracing::info!(
             "Registered {} providers{}",
             registry.providers.len(),
             if disable_env_fallback {
                 " (Vault only, no env fallback)"
             } else {
                 " (Vault + env fallback)"
             }
         );
         Ok(registry)
     }

     /// Register providers from environment variables if they aren't already registered.
     ///
     /// This function provides a convenience fallback for local development by reading
     /// API keys from environment variables when providers are not configured in Vault.
     ///
     /// # Supported Environment Variables
     ///
     /// - `OPENAI_API_KEY` → Registers OpenAI provider
     /// - `ANTHROPIC_API_KEY` → Registers Anthropic provider
     /// - `GOOGLE_API_KEY` → Registers Google provider
     /// - `OPENROUTER_API_KEY` → Registers OpenRouter provider
     /// - `HF_BASE_URL`/`HUGGINGFACE_BASE_URL` (+ optional `HF_TOKEN`/`HUGGINGFACE_API_KEY`) → Registers Hugging Face provider
     /// - `CODETETHER_LOCAL_CUDA=1` (or `LOCAL_CUDA_MODEL*`) → Registers Local CUDA provider
     ///
     /// # Security Warning
     ///
     /// Environment variables are less secure than Vault secrets because they:
     /// - Can be leaked via process listings (`ps eww`) or container inspection
     /// - May appear in debug logs or error messages
     /// - Persist in shell history and dotfiles
     /// - Are accessible to all child processes
     ///
     /// For production deployments, set `CODETETHER_DISABLE_ENV_FALLBACK=1` to disable
     /// this fallback mechanism entirely. See [`from_vault()`](#method.from_vault) for details.
     ///
     /// # Behavior
     ///
     /// This function only registers a provider if:
     /// 1. The provider is not already registered (via Vault or earlier initialization)
     /// 2. The corresponding environment variable is set and non-empty
     fn register_env_fallbacks(registry: &mut Self) {
         let fallbacks: &[(&str, &str, fn(String) -> Result<Arc<dyn Provider>>)] = &[
             ("openai", "OPENAI_API_KEY", |key| {
                 Ok(Arc::new(openai::OpenAIProvider::new(key)?))
             }),
             ("anthropic", "ANTHROPIC_API_KEY", |key| {
                 Ok(Arc::new(anthropic::AnthropicProvider::new(key)?))
             }),
             ("google", "GOOGLE_API_KEY", |key| {
                 Ok(Arc::new(google::GoogleProvider::new(key)?))
             }),
             ("openrouter", "OPENROUTER_API_KEY", |key| {
                 Ok(Arc::new(openrouter::OpenRouterProvider::new(key)?))
             }),
         ];

         for (provider_id, env_var, constructor) in fallbacks {
             if !registry.providers.contains_key(*provider_id)
                 && let Ok(api_key) = std::env::var(env_var)
             {
                 match constructor(api_key) {
                     Ok(p) => {
                         tracing::info!(
                             "Registered {} provider from {} env var",
                             provider_id,
                             env_var
                         );
                         registry.register(p);
                     }
                     Err(e) => tracing::warn!("Failed to init {} from env: {}", provider_id, e),
                 }
             }
         }

         if !registry.providers.contains_key("huggingface") {
             let huggingface_base_url = std::env::var("HF_BASE_URL")
                 .ok()
                 .or_else(|| std::env::var("HUGGINGFACE_BASE_URL").ok())
                 .or_else(|| std::env::var("HUGGINGFACE_ENDPOINT").ok());

             if let Some(base_url) = huggingface_base_url {
                 let api_key = std::env::var("HF_TOKEN")
                     .ok()
                     .or_else(|| std::env::var("HUGGINGFACE_API_KEY").ok())
                     .filter(|value| !value.trim().is_empty());

                 match openai::OpenAIProvider::with_base_url_optional_key(
                     api_key,
                     base_url,
                     "huggingface",
                 ) {
                     Ok(p) => {
                         tracing::info!(
                             "Registered huggingface provider from HF_BASE_URL/HUGGINGFACE_BASE_URL env vars"
                         );
                         registry.register(Arc::new(p));
                     }
                     Err(e) => tracing::warn!("Failed to init huggingface from env: {}", e),
                 }
             }
         }

         // GLM-5 FP8 on Vast.ai — requires GLM5_BASE_URL; GLM5_API_KEY is optional
         if !registry.providers.contains_key("glm5")
             && let Ok(base_url) = std::env::var("GLM5_BASE_URL")
         {
             let api_key = std::env::var("GLM5_API_KEY").unwrap_or_default();
             let model_name =
                 std::env::var("GLM5_MODEL").unwrap_or_else(|_| glm5::DEFAULT_MODEL.to_string());
             match glm5::Glm5Provider::with_model(api_key, base_url, model_name) {
                 Ok(p) => {
                     tracing::info!("Registered glm5 provider from GLM5_BASE_URL env var");
                     registry.register(Arc::new(p));
                 }
                 Err(e) => tracing::warn!("Failed to init glm5 from env: {}", e),
             }
         }

         if !registry.providers.contains_key("local_cuda") {
             let local_cuda_enabled = std::env::var("CODETETHER_LOCAL_CUDA")
                 .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
                 .unwrap_or(false);
             let model_name = std::env::var("LOCAL_CUDA_MODEL")
                 .or_else(|_| std::env::var("CODETETHER_LOCAL_CUDA_MODEL"))
                 .unwrap_or_else(|_| "qwen3.5-9b".to_string());
             let model_path = std::env::var("LOCAL_CUDA_MODEL_PATH")
                 .or_else(|_| std::env::var("CODETETHER_LOCAL_CUDA_MODEL_PATH"))
                 .ok();
             let tokenizer_path = std::env::var("LOCAL_CUDA_TOKENIZER_PATH")
                 .or_else(|_| std::env::var("CODETETHER_LOCAL_CUDA_TOKENIZER_PATH"))
                 .ok();
             let architecture = std::env::var("LOCAL_CUDA_ARCH")
                 .or_else(|_| std::env::var("CODETETHER_LOCAL_CUDA_ARCH"))
                 .ok();
             let has_model_env = std::env::var("LOCAL_CUDA_MODEL").is_ok()
                 || std::env::var("CODETETHER_LOCAL_CUDA_MODEL").is_ok();
             let has_local_cuda_config = has_model_env
                 || model_path.is_some()
                 || tokenizer_path.is_some()
                 || architecture.is_some();

             if local_cuda_enabled || has_local_cuda_config {
                 let provider = if let Some(path) = model_path {
                     local_cuda::LocalCudaProvider::with_paths(
                         model_name.clone(),
                         path,
                         tokenizer_path,
                         architecture,
                     )
                 } else {
                     local_cuda::LocalCudaProvider::new(model_name.clone())
                 };

                 match provider {
                     Ok(p) => {
                         tracing::info!(
                             model = %model_name,
                             "Registered local_cuda provider from environment"
                         );
                         registry.register(Arc::new(p));
                     }
                     Err(e) => tracing::warn!("Failed to init local_cuda from env: {}", e),
                 }
             }
         }
     }
 }

 fn normalize_minimax_anthropic_base_url(base_url: &str) -> String {
     let trimmed = base_url.trim().trim_end_matches('/');
     if trimmed.eq_ignore_ascii_case("https://api.minimax.io/v1") {
         "https://api.minimax.io/anthropic".to_string()
     } else {
         trimmed.to_string()
     }
 }

 impl Default for ProviderRegistry {
     fn default() -> Self {
         Self::new()
     }
 }

